#!/usr/bin/env node
'use strict';

const fs = require('fs');
const path = require('path');

const MINIGIT_DIR = '.minigit';
const OBJECTS_DIR = path.join(MINIGIT_DIR, 'objects');
const COMMITS_DIR = path.join(MINIGIT_DIR, 'commits');
const INDEX_FILE = path.join(MINIGIT_DIR, 'index');
const HEAD_FILE = path.join(MINIGIT_DIR, 'HEAD');

function miniHash(data) {
    let h = 1469598103934665603n;
    for (let i = 0; i < data.length; i++) {
        h ^= BigInt(data[i]);
        h = (h * 1099511628211n) % (1n << 64n);
    }
    return h.toString(16).padStart(16, '0');
}

function cmdInit() {
    if (fs.existsSync(MINIGIT_DIR)) {
        console.log('Repository already initialized');
        process.exit(0);
    }
    fs.mkdirSync(OBJECTS_DIR, { recursive: true });
    fs.mkdirSync(COMMITS_DIR, { recursive: true });
    fs.writeFileSync(INDEX_FILE, '');
    fs.writeFileSync(HEAD_FILE, '');
}

function cmdAdd(filename) {
    if (!filename) {
        console.error('Usage: minigit add <file>');
        process.exit(1);
    }
    if (!fs.existsSync(filename)) {
        console.log('File not found');
        process.exit(1);
    }
    const content = fs.readFileSync(filename);
    const hash = miniHash(content);
    fs.writeFileSync(path.join(OBJECTS_DIR, hash), content);

    const indexContent = fs.readFileSync(INDEX_FILE, 'utf8');
    const lines = indexContent ? indexContent.split('\n').filter(l => l.length > 0) : [];
    if (!lines.includes(filename)) {
        lines.push(filename);
        fs.writeFileSync(INDEX_FILE, lines.join('\n') + '\n');
    }
}

function cmdCommit(message) {
    if (!message) {
        console.error('Usage: minigit commit -m "<message>"');
        process.exit(1);
    }
    const indexContent = fs.readFileSync(INDEX_FILE, 'utf8').trim();
    if (!indexContent) {
        console.log('Nothing to commit');
        process.exit(1);
    }

    const filenames = indexContent.split('\n').filter(l => l.length > 0);
    filenames.sort();

    const head = fs.readFileSync(HEAD_FILE, 'utf8').trim();
    const parent = head || 'NONE';
    const timestamp = Math.floor(Date.now() / 1000);

    let commitContent = `parent: ${parent}\n`;
    commitContent += `timestamp: ${timestamp}\n`;
    commitContent += `message: ${message}\n`;
    commitContent += 'files:\n';

    for (const fname of filenames) {
        const content = fs.readFileSync(fname);
        const hash = miniHash(content);
        commitContent += `${fname} ${hash}\n`;
    }

    const commitHash = miniHash(Buffer.from(commitContent));
    fs.writeFileSync(path.join(COMMITS_DIR, commitHash), commitContent);
    fs.writeFileSync(HEAD_FILE, commitHash);
    fs.writeFileSync(INDEX_FILE, '');

    console.log(`Committed ${commitHash}`);
}

function cmdLog() {
    let current = fs.readFileSync(HEAD_FILE, 'utf8').trim();
    if (!current) {
        console.log('No commits');
        return;
    }

    let first = true;
    while (current && current !== 'NONE') {
        const commitPath = path.join(COMMITS_DIR, current);
        const content = fs.readFileSync(commitPath, 'utf8');

        let parentHash = '';
        let timestamp = '';
        let message = '';

        const lines = content.split('\n');
        for (const line of lines) {
            if (line.startsWith('parent: ')) {
                parentHash = line.substring(8);
            } else if (line.startsWith('timestamp: ')) {
                timestamp = line.substring(11);
            } else if (line.startsWith('message: ')) {
                message = line.substring(9);
            }
        }

        if (!first) {
            console.log('');
        }
        console.log(`commit ${current}`);
        console.log(`Date: ${timestamp}`);
        console.log(`Message: ${message}`);

        first = false;
        current = parentHash === 'NONE' ? '' : parentHash;
    }
}

// Main
const args = process.argv.slice(2);
const command = args[0];

switch (command) {
    case 'init':
        cmdInit();
        break;
    case 'add':
        cmdAdd(args[1]);
        break;
    case 'commit':
        if (args[1] === '-m') {
            cmdCommit(args[2]);
        } else {
            console.error('Usage: minigit commit -m "<message>"');
            process.exit(1);
        }
        break;
    case 'log':
        cmdLog();
        break;
    default:
        console.error('Unknown command: ' + command);
        process.exit(1);
}

