function cmdStatus() {
    const indexContent = fs.readFileSync(INDEX_FILE, 'utf8').trim();
    console.log('Staged files:');
    if (!indexContent) {
        console.log('(none)');
    } else {
        const lines = indexContent.split('\n').filter(l => l.length > 0);
        for (const line of lines) {
            console.log(line);
        }
    }
}

function parseCommit(hash) {
    const commitPath = path.join(COMMITS_DIR, hash);
    if (!fs.existsSync(commitPath)) return null;
    const content = fs.readFileSync(commitPath, 'utf8');
    const lines = content.split('\n');
    let parent = '', timestamp = '', message = '';
    const files = {};
    let inFiles = false;
    for (const line of lines) {
        if (line.startsWith('parent: ')) {
            parent = line.substring(8);
        } else if (line.startsWith('timestamp: ')) {
            timestamp = line.substring(11);
        } else if (line.startsWith('message: ')) {
            message = line.substring(9);
        } else if (line === 'files:') {
            inFiles = true;
        } else if (inFiles && line.length > 0) {
            const spaceIdx = line.lastIndexOf(' ');
            const fname = line.substring(0, spaceIdx);
            const blobHash = line.substring(spaceIdx + 1);
            files[fname] = blobHash;
        }
    }
    return { parent, timestamp, message, files };
}

function cmdDiff(hash1, hash2) {
    const c1 = parseCommit(hash1);
    const c2 = parseCommit(hash2);
    if (!c1 || !c2) {
        console.log('Invalid commit');
        process.exit(1);
    }
    const allFiles = new Set([...Object.keys(c1.files), ...Object.keys(c2.files)]);
    const sorted = [...allFiles].sort();
    for (const fname of sorted) {
        const in1 = fname in c1.files;
        const in2 = fname in c2.files;
        if (!in1 && in2) {
            console.log(`Added: ${fname}`);
        } else if (in1 && !in2) {
            console.log(`Removed: ${fname}`);
        } else if (in1 && in2 && c1.files[fname] !== c2.files[fname]) {
            console.log(`Modified: ${fname}`);
        }
    }
}

function cmdCheckout(hash) {
    const commit = parseCommit(hash);
    if (!commit) {
        console.log('Invalid commit');
        process.exit(1);
    }
    for (const [fname, blobHash] of Object.entries(commit.files)) {
        const blobContent = fs.readFileSync(path.join(OBJECTS_DIR, blobHash));
        fs.writeFileSync(fname, blobContent);
    }
    fs.writeFileSync(HEAD_FILE, hash);
    fs.writeFileSync(INDEX_FILE, '');
    console.log(`Checked out ${hash}`);
}

function cmdReset(hash) {
    const commit = parseCommit(hash);
    if (!commit) {
        console.log('Invalid commit');
        process.exit(1);
    }
    fs.writeFileSync(HEAD_FILE, hash);
    fs.writeFileSync(INDEX_FILE, '');
    console.log(`Reset to ${hash}`);
}

function cmdRm(filename) {
    const indexContent = fs.readFileSync(INDEX_FILE, 'utf8').trim();
    const lines = indexContent ? indexContent.split('\n').filter(l => l.length > 0) : [];
    const idx = lines.indexOf(filename);
    if (idx === -1) {
        console.log('File not in index');
        process.exit(1);
    }
    lines.splice(idx, 1);
    fs.writeFileSync(INDEX_FILE, lines.length > 0 ? lines.join('\n') + '\n' : '');
}

function cmdShow(hash) {
    const commit = parseCommit(hash);
    if (!commit) {
        console.log('Invalid commit');
        process.exit(1);
    }
    console.log(`commit ${hash}`);
    console.log(`Date: ${commit.timestamp}`);
    console.log(`Message: ${commit.message}`);
    console.log('Files:');
    const sorted = Object.keys(commit.files).sort();
    for (const fname of sorted) {
        console.log(`  ${fname} ${commit.files[fname]}`);
    }
}

// Main
const args = process.argv.slice(2);
const command = args[0];

switch (command) {
    case 'init':
        cmdInit();
        break;
    case 'add':
        cmdAdd(args[1]);
        break;
    case 'commit':
        if (args[1] === '-m') {
            cmdCommit(args[2]);
        } else {
            console.error('Usage: minigit commit -m "<message>"');
            process.exit(1);
        }
        break;
    case 'status':
        cmdStatus();
        break;
    case 'log':
        cmdLog();
        break;
    case 'diff':
        cmdDiff(args[1], args[2]);
        break;
    case 'checkout':
        cmdCheckout(args[1]);
        break;
    case 'reset':
        cmdReset(args[1]);
        break;
    case 'rm':
        cmdRm(args[1]);
        break;
    case 'show':
        cmdShow(args[1]);
        break;
    default:
        console.error('Unknown command: ' + command);
        process.exit(1);
}

